+async function runJsonFallback(opts: {
+  argv: string[];
+  cwd?: string;
+  timeoutMs: number;
+}): Promise<{
+  stdout: string;
+  stderr: string;
+  code: number;
+  signal?: NodeJS.Signals | null;
+  killed?: boolean;
+}> {
+  return await new Promise((resolve, reject) => {
+    const child = spawn(opts.argv[0], opts.argv.slice(1), {
+      cwd: opts.cwd,
+      stdio: ["ignore", "pipe", "pipe"],
+    });
+    let stdout = "";
+    let stderr = "";
+    const timer = setTimeout(() => {
+      child.kill("SIGKILL");
+      reject(
+        new Error(
+          `pi json fallback timed out after ${Math.round(opts.timeoutMs / 1000)}s`,
+        ),
+      );
+    }, opts.timeoutMs);
+    child.stdout.on("data", (d) => {
+      stdout += d.toString();
+    });
+    child.stderr.on("data", (d) => {
+      stderr += d.toString();
+    });
+    child.on("error", (err) => {
+      clearTimeout(timer);
+      reject(err);
+    });
+    child.on("exit", (code, signal) => {
+      clearTimeout(timer);
+      resolve({
+        stdout,
+        stderr,
+        code: code ?? 0,
+        signal,
+        killed: child.killed,
+      });
+    });
+  });
+}
